#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005;
const ll inf=1e17;
ll n,m,s,t,k,fir[N],fa[N],mx[N],num[N],S,T;//mx和num是题目里的 
struct node
{
	ll v,w,fan;
};
ll lev[N];
vector<node> g[N];
void add(int u,int v,ll w)
{
	g[u].push_back(node{v,w,g[v].size()});
	g[v].push_back(node{u,0,g[u].size()-1});
}
bool bfs()
{
	for(int i=1;i<=N-5;i++)
	{
		lev[i]=inf;
		fir[i]=0;
	}
	queue<int> q;
	q.push(S);
	lev[S]=0;
	while(!q.empty())
	{
		int u=q.front();
		q.pop();
		for(int i=0;i<g[u].size();i++)
		{
			int v=g[u][i].v,w=g[u][i].w;
			if((w>0)&&(lev[v]==inf))
			{
				q.push(v);
				lev[v]=lev[u]+1;
				if(v==T) return 1;
			}
		}
	}
	return 0;
}
ll dfs(int u,ll mn)
{
	if(u==T) return mn;
	ll ans=0;
	for(int i=fir[u];i<g[u].size();i++)
	{
		fir[u]=i;
		ll v=g[u][i].v,w=g[u][i].w;
		if((w>0)&&(lev[v]==lev[u]+1))
		{
			ll num=dfs(v,min(mn,(ll)w));
			if(num==0) lev[v]=inf;
			g[u][i].w-=num;
			g[v][g[u][i].fan].w+=num;
			ans+=num;
			mn-=num;
		}
	}
	return ans;
}
int find(int x)
{
	if(x==fa[x]) return x;
	return fa[x]=find(fa[x]);
}
vector<int> v[N];
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m>>k;
	for(int i=1;i<=n+2;i++)
	{
		fa[i]=i;
	}
	s=4,t=3;S=1,T=2;
	for(int i=1;i<=m;i++)
	{
		cin>>mx[i]>>num[i];
		int lst;
		for(int j=1;j<=num[i];j++)
		{
			int x;
			cin>>x;
			x+=2;
			v[i].push_back(x);
			if(j-1)
			{
				int fx=find(x),fy=find(lst);
				if(fx!=fy) fa[fx]=fy;
			}
			lst=x;
		}
	}
	if(find(1)!=find(2))
	{
		cout<<0;
		return 0;
	}
	n+=2;
	add(S,s,inf);
	add(t,T,inf);
	int tim=0;
	ll ans=0;
	while(true)
	{
		tim++;
//		cout<<tim<<endl;
		for(int i=1;i<=m;i++)
		{
			int u=v[i][(tim-1+num[i])%num[i]],vv=v[i][tim%num[i]];
            u+=2;
            vv+=2;
			add((tim-1)*n+u,tim*n+vv,mx[i]);
		}
		add(S,s+n*tim,inf);
		add(tim*n+t,T,inf);
		for(int j=1;j<=n;j++)
		{
			add((tim-1)*n+j+2,tim*n+j+2,inf);
		}
		while(bfs())
		{
			ans+=dfs(S,inf);
		}
		if(ans>=k)
		{
			cout<<tim;
			return 0;
		}
	}
	return 0;
}
